const body = $json.body || $json;

function s(v) {
  return v == null ? '' : String(v);
}

return {
  json: {
    segment_id: s(body.segment_id),
    task_id: s(body.task_id),
    prompt: s(body.prompt),
    product_image_url: s(body.product_image_url),
    reference_frame_url: s(body.reference_frame_url),
    image_edit_mode: s(body.image_edit_mode || 'product_replace'),
    model: s(body.model || 'nanoBananapro'),
    aspect_ratio: s(body.aspect_ratio || '9:16'),
    callback_url: s(body.callback_url),
    api_key: s(body.api_key),
    admin_token: s(body.admin_token),
    workflow_id: s(body.workflow_id || 'flow_image_video_Veo')
  }
};

const j = $json || {};

function s(v) {
  return v == null ? '' : String(v).trim();
}

function pushInline(parts, { b64, mimeType, label }) {
  if (!b64) return;
  parts.push({ text: label });
  parts.push({
    inline_data: {
      mime_type: mimeType || 'image/jpeg',
      data: b64,
    }
  });
}

const prod_b64 = s(j.product_image_b64);
const prod_mime = s(j.product_mime_type || 'image/jpeg');
const ref_b64 = s(j.reference_frame_b64);
const ref_mime = s(j.reference_frame_mime || 'image/jpeg');

const prompt = s(j.prompt) || 'Generate a high quality product replacement image';
const ratio = s(j.aspect_ratio || '9:16');

const parts = [];
parts.push({
  text: [
    prompt,
    '',
    'Reference image rules:',
    '- Image 1, if present, is PRODUCT reference. Use it only to replace the product identity, shape, material, package, and visible brand structure.',
    '- Image 2, if present, is REFERENCE FRAME. Use it as the primary anchor for composition, crop, camera height, subject placement, scene layout, lighting direction, shadow logic, and storytelling purpose.',
    '- Do not import any person, face, model, celebrity, or character identity reference.',
    '- If people appear in the reference frame, keep them generic and natural; do not preserve or copy a real person identity.',
    '- Preserve the original shot design and viral ad grammar. Replace only the product where applicable.',
    '- No subtitles, UI overlays, watermark, border, collage, extra products, or product deformation.'
  ].join('\n')
});

if (prod_b64) {
  pushInline(parts, {
    b64: prod_b64,
    mimeType: prod_mime,
    label: 'Image 1 - PRODUCT reference for product replacement'
  });
}

if (ref_b64) {
  pushInline(parts, {
    b64: ref_b64,
    mimeType: ref_mime,
    label: prod_b64
      ? 'Image 2 - REFERENCE FRAME for composition and scene replication'
      : 'Image 1 - REFERENCE FRAME for composition and scene replication'
  });
}

const request_body = {
  contents: [{ role: 'user', parts }],
  generationConfig: {
    responseModalities: ['IMAGE'],
    imageConfig: { aspectRatio: ratio }
  }
};

const modelMap = {
  nanoBananapro: 'gemini-3-pro-image-preview',
  nanoBanana2: 'gemini-3.1-flash-image-preview'
};

return {
  json: {
    ...j,
    request_body,
    api_model: modelMap[s(j.model)] || 'gemini-3-pro-image-preview'
  }
};

function unwrapRoot(x) {
  if (x && typeof x === 'object' && x.body && typeof x.body === 'object') return x.body;
  return x;
}

function findInlineImageParts(root) {
  const candidates = root?.candidates;
  if (!Array.isArray(candidates) || !candidates.length) return [];
  const parts = candidates?.[0]?.content?.parts;
  if (!Array.isArray(parts)) return [];
  const imgs = [];
  for (const p of parts) {
    const inline = p?.inline_data || p?.inlineData;
    if (inline?.data) {
      imgs.push({ b64: inline.data, mimeType: inline.mime_type || inline.mimeType || 'image/png' });
      continue;
    }
    const fd = p?.fileData;
    if (fd?.fileUri) {
      imgs.push({ fileUri: fd.fileUri, mimeType: fd.mimeType || 'image/png' });
    }
  }
  return imgs;
}

function stripDataPrefix(b64) {
  return String(b64 || '').replace(/^data:.*;base64,/, '').trim();
}

const raw = $json || {};
const root = unwrapRoot(raw);
const imgs = findInlineImageParts(root);
const first = imgs[0];
if (!first || !first.b64) throw new Error('未从生图响应中解析到 inline image');

const mimeType = first.mimeType || 'image/png';
const ext = /png/i.test(mimeType) ? 'png' : (/webp/i.test(mimeType) ? 'webp' : 'jpg');
const b64 = stripDataPrefix(first.b64);
if (!b64) throw new Error('图片 base64 为空');

return {
  json: {
    mimeType,
    fileName: `storyboard_segment_${Date.now()}.${ext}`
  },
  binary: {
    data: {
      data: b64,
      mimeType,
      fileName: `storyboard_segment_${Date.now()}.${ext}`
    }
  }
};

const uploadResp = $input.item.json;
const imageUrl = uploadResp.url || '';

return {
  json: {
    image_url: imageUrl
  }
};

const j = $json || {};

function s(v) {
  return v == null ? '' : String(v);
}

async function readBinaryBase64(keyCandidates) {
  const keys = Object.keys($binary || {});
  let hitKey = '';

  for (const k of keyCandidates) {
    if (keys.includes(k)) {
      hitKey = k;
      break;
    }
  }

  if (!hitKey) {
    return {
      ok: false,
      key: '',
      b64: '',
      mime: '',
      fileName: '',
      fileSize: 0,
      error: 'missing binary key, existing: ' + keys.join(', ')
    };
  }

  const meta = $binary[hitKey] || {};

  try {
    const buf = await this.helpers.getBinaryDataBuffer(0, hitKey);

    return {
      ok: true,
      key: hitKey,
      b64: buf.toString('base64'),
      mime: s(meta.mimeType || 'image/jpeg'),
      fileName: s(meta.fileName || ''),
      fileSize: meta.fileSize || 0,
      error: ''
    };
  } catch (e) {
    return {
      ok: false,
      key: hitKey,
      b64: '',
      mime: s(meta.mimeType || ''),
      fileName: s(meta.fileName || ''),
      fileSize: meta.fileSize || 0,
      error: 'read buffer failed: ' + (e.message || e)
    };
  }
}

const productImg = await readBinaryBase64(['product_file']);
const referenceImg = await readBinaryBase64(['reference_file', 'frame_file']);

return {
  json: {
    ...j,
    product_image_b64: productImg.ok ? productImg.b64 : '',
    product_mime_type: productImg.ok ? productImg.mime : '',
    reference_frame_b64: referenceImg.ok ? referenceImg.b64 : '',
    reference_frame_mime: referenceImg.ok ? referenceImg.mime : '',
    debug_b64: {
      binary_keys: Object.keys($binary || {}),
      product: productImg,
      reference: referenceImg
    }
  },
  binary: $binary
};
